import{_ as e,o as s,c as n,a3 as t}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"ZooKeeper 事务日志损坏与恢复","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/zk-transaction-log-recovery.md","filePath":"middleware/kafka/zk-transaction-log-recovery.md","lastUpdated":1780474575000}'),i={name:"middleware/kafka/zk-transaction-log-recovery.md"};function p(l,a,d,o,r,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="zookeeper-shi-wu-ri-zhi-sun-pi-yu-hui-fu" tabindex="-1">ZooKeeper 事务日志损坏与恢复 <a class="header-anchor" href="#zookeeper-shi-wu-ri-zhi-sun-pi-yu-hui-fu" aria-label="Permalink to &quot;ZooKeeper 事务日志损坏与恢复&quot;">​</a></h1><p>本文分析一个真实的 ZooKeeper 事务日志损坏案例，日志来源是 K8s 环境中 Kafka 集群的 ZK 节点（<code>zookeeper-kafka-1</code>）启动时产生。</p><h2 id="bei-jing" tabindex="-1">背景 <a class="header-anchor" href="#bei-jing" aria-label="Permalink to &quot;背景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>值</th></tr></thead><tbody><tr><td>ZooKeeper 版本</td><td>3.6.3</td></tr><tr><td>运行环境</td><td>Kubernetes StatefulSet，namespace <code>kafka</code></td></tr><tr><td>节点角色</td><td>myid=2，FOLLOWER</td></tr><tr><td>集群规模</td><td>3 节点 ZK 集群</td></tr><tr><td>部署方式</td><td>Headless Service + StatefulSet</td></tr></tbody></table><h2 id="gu-zhang-xian-xiang" tabindex="-1">故障现象 <a class="header-anchor" href="#gu-zhang-xian-xiang" aria-label="Permalink to &quot;故障现象&quot;">​</a></h2><p>ZK 节点启动时出现大量 ERROR 日志：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026-06-02 10:41:57,412 [myid:2] - ERROR [main:Util@166] - Last transaction was partial.</span></span>
<span class="line"><span>2026-06-02 10:41:58,712 [myid:2] - ERROR [main:Util@166] - Last transaction was partial.</span></span>
<span class="line"><span>2026-06-02 10:42:00,510 [myid:2] - ERROR [main:FileTxnSnapLog@336] - 133144055776(highestZxid) &gt; 133144055743(next log) for type -10</span></span>
<span class="line"><span>2026-06-02 10:42:00,511 [myid:2] - ERROR [main:FileTxnSnapLog@336] - 133144055776(highestZxid) &gt; 133144055744(next log) for type -11</span></span>
<span class="line"><span>...</span></span></code></pre></div><ul><li><strong>&quot;Last transaction was partial&quot;</strong>：最后一条事务日志不完整（写入到一半时进程终止）</li><li><strong>&quot;highestZxid &gt; next log&quot;</strong>：快照期望的事务 ID 大于实际日志文件中的下一条事务 ID，说明快照和事务日志之间存在<strong>断层</strong></li><li><strong>type -10 / -11</strong>：这些是 Apache BookKeeper 的操作类型，表明上层使用了 BookKeeper 做分布式日志存储</li></ul><h2 id="gen-yin-fen-xi" tabindex="-1">根因分析 <a class="header-anchor" href="#gen-yin-fen-xi" aria-label="Permalink to &quot;根因分析&quot;">​</a></h2><h3 id="shi-wu-ri-zhi-xie-ru-ji-zhi" tabindex="-1">事务日志写入机制 <a class="header-anchor" href="#shi-wu-ri-zhi-xie-ru-ji-zhi" aria-label="Permalink to &quot;事务日志写入机制&quot;">​</a></h3><p>ZooKeeper 每次状态变更都采用<strong>先写事务日志（Write-Ahead Log）再更新内存</strong>的顺序：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client Request</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Leader 接收写请求 → 生成 Proposal → 广播给所有 Follower</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Follower 收到 Proposal → 写入 txn log → 返回 ACK</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── 超半数 ACK → Leader commit → 更新内存 DataTree</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         └── 定期 snapshot（快照序列化 DataTree 到磁盘）</span></span></code></pre></div><h3 id="sun-pi-yuan-yin" tabindex="-1">损坏原因 <a class="header-anchor" href="#sun-pi-yuan-yin" aria-label="Permalink to &quot;损坏原因&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常流程:</span></span>
<span class="line"><span>  ┌─────────────┐     ┌──────────────┐     ┌──────────────┐</span></span>
<span class="line"><span>  │ 写入 txn log │ ──► │ fsync 到磁盘  │ ──► │ 更新 zxid    │</span></span>
<span class="line"><span>  └─────────────┘     └──────────────┘     └──────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>异常终止:</span></span>
<span class="line"><span>  ┌─────────────┐     ┌──────────────┐     X 进程被 kill</span></span>
<span class="line"><span>  │ 写入 txn log │ ──► │ 部分 fsync    │ ──► │ zxid 未更新  │</span></span>
<span class="line"><span>  └─────────────┘     └──────────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>    磁盘上有半条事务记录 → &quot;Last transaction was partial&quot;</span></span></code></pre></div><p>K8s 环境中常见触发场景：</p><table tabindex="0"><thead><tr><th>原因</th><th>说明</th></tr></thead><tbody><tr><td>Pod OOMKilled</td><td>内存超限被 Kubelet 杀死</td></tr><tr><td>Node 驱逐</td><td>节点资源不足，Pod 被驱逐</td></tr><tr><td>强制删除</td><td><code>kubectl delete pod --force --grace-period=0</code></td></tr><tr><td>节点故障</td><td>物理机宕机，无优雅关闭</td></tr><tr><td>PreStop hook 缺失</td><td>StatefulSet 未配置 <code>lifecycle.preStop</code>，终止信号后直接 SIGTERM</td></tr></tbody></table><h3 id="zxid-bu-pi-pei" tabindex="-1">zxid 不匹配 <a class="header-anchor" href="#zxid-bu-pi-pei" aria-label="Permalink to &quot;zxid 不匹配&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Snapshot 中最高 zxid:  0x1e000004af (快照时刻的事务 ID)</span></span>
<span class="line"><span>快照后产生的事务:       log.5900002c8a (日志文件名编码了起始 zxid)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>gap = 0x5900002c8a - 0x1e000004af = 大量的后续事务</span></span></code></pre></div><p>快照是定期生成的（默认 <code>snapCount=100000</code>，即每 10 万条事务做一次快照），两次快照之间的事务日志文件是增量。如果最近的事务日志损坏，快照仍然是可用的。</p><h2 id="hui-fu-guo-cheng" tabindex="-1">恢复过程 <a class="header-anchor" href="#hui-fu-guo-cheng" aria-label="Permalink to &quot;恢复过程&quot;">​</a></h2><p>ZooKeeper 的恢复过程分三个阶段：</p><h3 id="1-jia-zai-ben-di-kuai-zhaosnapshot" tabindex="-1">1. 加载本地快照（Snapshot） <a class="header-anchor" href="#1-jia-zai-ben-di-kuai-zhaosnapshot" aria-label="Permalink to &quot;1. 加载本地快照（Snapshot）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026-06-02 10:41:40,808 [myid:2] - INFO  [main:FileSnap@85] - Reading snapshot /data/version-2/snapshot.1e000004af</span></span>
<span class="line"><span>2026-06-02 10:42:03,108 [myid:2] - INFO  [main:FileTxnSnapLog@363] - 86470 txns loaded in 20601 ms</span></span>
<span class="line"><span>2026-06-02 10:42:03,109 [myid:2] - INFO  [main:ZKDatabase@289] - Snapshot loaded in 22898 ms, highest zxid is 0x5900002c89</span></span></code></pre></div><ul><li>从最新有效快照恢复 DataTree</li><li>重放快照之后的有效事务日志（86470 条），耗时约 20s</li><li>快照最高 zxid 为 <code>0x5900002c89</code>，已恢复到快照关闭前的状态</li></ul><blockquote><p>损坏的事务日志 ERROR 只是警告信息，ZK 会跳过这些损坏的日志记录。日志行 112-143 显示大约 32 条损坏的事务被跳过（<code>highestZxid &gt; next log</code>），这些事务原本应该存在于快照关闭之后，但由于日志损坏无法恢复。</p></blockquote><h3 id="2-leader-xuan-ju" tabindex="-1">2. Leader 选举 <a class="header-anchor" href="#2-leader-xuan-ju" aria-label="Permalink to &quot;2. Leader 选举&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026-06-02 10:42:08,109 [myid:2] - INFO  - LOOKING</span></span>
<span class="line"><span>2026-06-02 10:42:08,210 [myid:2] - INFO  - New election. My id = 2, proposed zxid=0x5900002c89</span></span>
<span class="line"><span>2026-06-02 10:42:10,112 [myid:2] - INFO  - FOLLOWING</span></span>
<span class="line"><span>2026-06-02 10:42:11,011 [myid:2] - INFO  - LEADER ELECTION TOOK - 2801 MS</span></span></code></pre></div><ul><li>节点进入 LOOKING 状态，发起选举</li><li>收到 myid=3 (LEADING, zxid=0x5800000005) 和 myid=1 (FOLLOWING, leader=3) 的通知</li><li>本节点 zxid 更高但 Leader 已经确认，转为 FOLLOWING</li><li>选举耗时 2.8 秒</li></ul><h3 id="3-leader-tong-budiff-tong-bu" tabindex="-1">3. Leader 同步（Diff 同步） <a class="header-anchor" href="#3-leader-tong-budiff-tong-bu" aria-label="Permalink to &quot;3. Leader 同步（Diff 同步）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026-06-02 10:42:11,508 [myid:2] - INFO  [Learner@551] - Getting a diff from the leader 0x5900002d3f</span></span>
<span class="line"><span>2026-06-02 10:42:13,510 [myid:2] - INFO  [Learner@701] - Learner received UPTODATE message</span></span></code></pre></div><ul><li>从 Leader 拉取缺失的事务（zxid <code>0x5900002c8a</code> 到 <code>0x5900002d3f</code>，约 182 条）</li><li>通过 diff 方式同步（只同步差异，而非全量 SNAP 同步），说明大部分数据一致</li><li>收到 UPTODATE 后进入 BROADCAST 状态，正式对外服务</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026-06-02 10:42:13,809 [myid:2] - INFO  [QuorumPeer@864] - Peer state changed: following - broadcast</span></span></code></pre></div><h3 id="hui-fu-shi-jian-xian" tabindex="-1">恢复时间线 <a class="header-anchor" href="#hui-fu-shi-jian-xian" aria-label="Permalink to &quot;恢复时间线&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10:41:25  读取配置</span></span>
<span class="line"><span>10:41:40  开始加载快照</span></span>
<span class="line"><span>10:42:03  快照加载完成（22.9s），zxid=0x5900002c89</span></span>
<span class="line"><span>  ↓  Leader 选举</span></span>
<span class="line"><span>10:42:11  完成选举，转为 FOLLOWING（2.8s）</span></span>
<span class="line"><span>  ↓  Leader 同步</span></span>
<span class="line"><span>10:42:13  同步完成（2.0s）</span></span>
<span class="line"><span>10:42:13  进入 BROADCAST，对外服务</span></span>
<span class="line"><span>───────────────────────────</span></span>
<span class="line"><span>总恢复时间: ~48 秒</span></span></code></pre></div><h2 id="zong-jie" tabindex="-1">总结 <a class="header-anchor" href="#zong-jie" aria-label="Permalink to &quot;总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>要点</th><th>说明</th></tr></thead><tbody><tr><td>故障本质</td><td>Pod 异常终止导致事务日志写入不完整</td></tr><tr><td>恢复手段</td><td>快照恢复 + 跳过损坏日志 + Leader diff 同步</td></tr><tr><td>数据安全</td><td>3 节点多数派 + 快照机制保证了数据完整性，未丢失已提交数据</td></tr><tr><td>恢复时间</td><td>~48s（快照加载 23s + 选举 3s + 同步 2s）</td></tr></tbody></table><h3 id="yu-fang-cuo-shi" tabindex="-1">预防措施 <a class="header-anchor" href="#yu-fang-cuo-shi" aria-label="Permalink to &quot;预防措施&quot;">​</a></h3><table tabindex="0"><thead><tr><th>措施</th><th>说明</th></tr></thead><tbody><tr><td>配置 PreStop hook</td><td>StatefulSet 中设置 <code>lifecycle.preStop</code>，给 ZK 足够时间优雅关闭</td></tr><tr><td>增加资源 limit</td><td>合理设置 JVM heap 和 memory limit，避免 OOMKilled</td></tr><tr><td>使用 PodDisruptionBudget</td><td>限制同时不可用的 ZK Pod 数量</td></tr><tr><td>监控 ZK 指标</td><td>关注 <code>fsync</code> 耗时、pending syncs、outstanding requests</td></tr><tr><td>KRaft 迁移</td><td>长期方案：迁移到 KRaft 模式，消除 ZK 依赖</td></tr></tbody></table><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://zookeeper.apache.org/doc/r3.6.3/zookeeperAdmin.html" target="_blank" rel="noreferrer">ZooKeeper Administrator&#39;s Guide</a></li><li><a href="https://bookkeeper.apache.org/" target="_blank" rel="noreferrer">Apache BookKeeper</a></li><li><a href="https://kafka.apache.org/documentation/#kraft" target="_blank" rel="noreferrer">Kafka KRaft Migration</a></li></ul>`,40)])])}const g=e(i,[["render",p]]);export{u as __pageData,g as default};
